    const parsedLimit = parseInt(limit, 10);
    const parsedOffset = parseInt(offset, 10);

    const safeLimit = !isNaN(parsedLimit) && parsedLimit > 0 && parsedLimit <= 100
      ? parsedLimit
      : 20; // default
    const safeOffset = !isNaN(parsedOffset) && parsedOffset >= 0
      ? parsedOffset
      : 0;

    // In production: fetch from DB using safeLimit/safeOffset
    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ].slice(safeOffset, safeOffset + safeLimit);

    res.json(users);
  } catch (err) {
    next(err); // forward to error handler
  }
});

// --- 404 handler for unknown routes ---
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Centralized error handler ---
// Must have exactly 4 params for Express to treat it as an error handler
app.use((err, req, res, next) => { // eslint-disable-line no-unused-vars
  console.error(`[${new Date().toISOString()}] Error:`, err.message);

  // Never leak stack traces or internal details to the client
  const status = err.status || err.statusCode || 500;
  res.status(status).json({
    error: status < 500 ? err.message : 'Internal server error',
  });
});

// --- Configurable port via environment variable ---
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

