```js
'use strict';

const express = require('express');
const helmet = require('helmet');           // npm install helmet
const rateLimit = require('express-rate-limit'); // npm install express-rate-limit

const app = express();
const PORT = process.env.PORT || 3000;

// --- Security headers ---
app.use(helmet());

// --- Body parsing (with size limit to prevent payload attacks) ---
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// --- Rate limiting ---
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
});
app.use(limiter);

// --- Routes ---
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  // TODO: Add authentication/authorization before returning user data
  res.json([
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ]);
});

// --- 404 handler ---
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Global error handler (must have 4 params for Express to treat it as error middleware) ---
// eslint-disable-next-line no-unused-vars
app.use((err, req, res, next) => {
  const status = err.status || err.statusCode || 500;
  // Never leak internal error details to clients in production
  const message =
    process.env.NODE_ENV === 'production'
      ? 'Internal server error'
      : err.message;

  console.error(`[${new Date().toISOString()}] ${status} - ${err.message}`);
  res.status(status).json({ error: message });
});

// --- Start server (only when run directly, not when required in tests) ---
if (require.main === module) {
  app.listen(PORT, () => {
    console.log(`Server running on port ${PORT}`);
  });
}

module.exports = app;
```

